// Map of lowercase keywords to their token IDs
const keywords = {
  select: select,
  not: not,
  true: _true,
  false: _false,
  null: _null,
  like: like,
  between: between,
  in: _in,
  is: is,
  and: and,
  or: or,
  as: as,
  from: from,
  inner: inner,
  left: left,
  right: right,
  full: full,
  cross: cross,
  unnest: unnest,
  join: join,
  on: on,
  where: where,
  group: group,
  by: by,
  order: order,
  asc: asc,
  desc: desc,
  limit: limit,
  offset: offset,
  table: table,
  exists: exists,
  primary_key: primary_key,
  interval: interval,
  date: date,
  timestamp: timestamp,
  case: _case,
  when: when,
  then: then,
  else: _else,
  end: end,
  count: count,
  extract: extract,
  cast: cast,
  array: array,
  distinct: distinct,
  union: union,
  all: all,
  intersect: intersect,
  except: except,
  having: having,
  one: one,
  many: many,
  extend: extend,
  with: _with,
  over: over,
  partition: partition,
  rows: rows,
  range: range,
  preceding: preceding,
  following: following,
  current: current,
  row: row,
  unbounded: unbounded,
}

export function specializeIdentifier(value) {
  let lower = value.toLowerCase()
  return keywords[lower] || -1
}
